import sys

def process_line(line):
    # Split the line at '|' to ignore distractors
    line = line.split('|')[0].strip()
    # Extract the name and numbers using regex
    import re
    match = re.match(r'^(\w+) (?:has|had|has) (\d+) (?:apples|candies|marbles)(?: and buys| and gave| and gives away)? (\d+)?$', line)
    if match:
        name = match.group(1)
        N = int(match.group(2))
        if match.group(3):
            M = int(match.group(3))
            # Pattern 1
            return N + M
        else:
            # Check for patterns 2 and 3
            if 'gave' in line or 'gives away' in line:
                M = int(re.search(r'gave (\d+)', line).group(1))
                if M <= N:
                    return N - M
                else:
                    return 'INVALID'
    return 'INVALID'

